    private onArenaStatusEvent(event: ArenaStatusMessageEvent): void {
        const parser = event.getParser();
        if (!parser) return;

        const hasSelf = parser.selfId > 0 && !!parser.selfUsername;
        const hasOpponent = parser.oppId > 0 && !!parser.oppUsername;

        const payload = {
            inQueue: parser.inQueue,
            isMatched: parser.isMatched,

            self: hasSelf
                ? {
                      userId: parser.selfId,
                      username: parser.selfUsername,
                      figure: parser.selfFigure,
                      level: parser.selfLevel,
                      wins: parser.selfWins,
                      losses: parser.selfLosses,
                  }
                : null,

            // opponent is present whenever oppId > 0, match state is still
            // decided by inQueue + isMatched on the React side
            opponent: hasOpponent
                ? {
                      userId: parser.oppId,
                      username: parser.oppUsername,
                      figure: parser.oppFigure,
                      level: parser.oppLevel,
                      wins: parser.oppWins,
                      losses: parser.oppLosses,
                  }
                : null,
        };

        window.dispatchEvent(
            new CustomEvent('arena_status', { detail: payload })
        );

        // console.log('[⚔️] Arena status update:', payload);
    }
