   private _policeCallDedup: Map<string, number> = new Map();

private onPoliceCallEvent(event: PoliceCallEvent): void {
const parser = event.getParser();
if (!parser) return;

const { username, figure, message, virtualRoomId, virtualRoomName } = parser.data;

// --- dedupe (in case packet fires twice) ---
const now = Date.now();
const key = `${username}|${virtualRoomId}|${virtualRoomName}|${message}`;

const last = this._policeCallDedup.get(key) || 0;
if (now - last < 1500) return;

this._policeCallDedup.set(key, now);

// cleanup old keys
if (this._policeCallDedup.size > 200) {
for (const [k, t] of this._policeCallDedup.entries()) {
if (now - t > 60_000) this._policeCallDedup.delete(k);
}
}

// ✅ ONLY this event — used by your PoliceCallView and/or bridge logic
window.dispatchEvent(
new CustomEvent("police_call_received", {
detail: {
username,
figure,
message: String(message ?? ""),
virtualRoomId: Number(virtualRoomId ?? 0),
virtualRoomName: String(virtualRoomName ?? ""),
},
})
);
}


