    private onGangStatusEvent(event: GangStatusEvent): void {
        try {
            const parser = event.getParser?.();
            if (!parser) return;

            const data = parser.data;

            // Persist for instant UI hydration on next open
            (window as any).__lastGangStatus = data;

            // Always tell the UI the latest status (even if not in a gang) so it can clear state
            window.dispatchEvent(
                new CustomEvent('gang_status_result', { detail: data })
            );
            window.dispatchEvent(
                new CustomEvent('gang_status_received', { detail: data })
            );

            // Small microtask delay lets listeners attach first
            setTimeout(() => {
                // Close both views first (listeners should noop if already closed)
                window.dispatchEvent(new CustomEvent('close-gang-details'));
                window.dispatchEvent(new CustomEvent('close-create-gang'));

                // Open the appropriate view
                window.dispatchEvent(
                    new CustomEvent(
                        data.inGang ? 'open-gang-details' : 'open-create-gang',
                        { detail: data }
                    )
                );

                // Optional: if in gang, proactively refresh members/ranks
                if (data.inGang) {
                    window.dispatchEvent(
                        new CustomEvent('request_gang_members')
                    );
                    window.dispatchEvent(new CustomEvent('request_gang_ranks'));
                }
            }, 10);
        } catch (err) {
            console.error('[GangBridge] onGangStatusEvent error:', err);
        }
    }

