    private onGangInviteEvent(event: GangInviteEvent): void {
        const parser = event.getParser();
        if (!parser) return;

        const inviterId: number = parser.inviterId;
        const inviterUsername: string = parser.inviterUsername;
        const gangName: string = parser.gangName;

        // Check user setting — default true if never set
        let invitesEnabled = true;
        try {
            const raw = localStorage.getItem('gangInvitesEnabled');
            if (raw !== null) invitesEnabled = JSON.parse(raw);
        } catch {}

        if (!invitesEnabled) {
            return; // don't show popup, don't send decline
        }

        // Fire popup if invites are enabled
        window.dispatchEvent(
            new CustomEvent('gang_invite_popup', {
                detail: {
                    inviter: inviterUsername,
                    inviterId: inviterId,
                    gangName: gangName,
                },
            })
        );
    }

