    private onTurfCaptureProgressEvent(event: TurfCaptureProgressEvent): void {
        const p = event.getParser();
        if (!p) return;

        const d: any = p.data;

        const state = d.active
            ? d.contested
                ? 'contested'
                : 'capturing'
            : d.percent >= 100
            ? 'captured'
            : 'canceled';

        // pick colors from ANY of the names we might receive
        const primary =
            d.defenderPrimaryColor || d.ownerPrimaryColor || d.ownerClrA || '';
        const secondary =
            d.defenderSecondaryColor ||
            d.ownerSecondaryColor ||
            d.ownerClrB ||
            '';

        const ownerGangId = d.defenderGangId || 0;
        const ownerGangName = d.defenderGangName || '';

        const payload = {
            turfId: (d.turfId || '').toUpperCase(),
            virtualRoomId: d.virtualRoomId || 0,
            state,
            progress: Math.max(0, Math.min(100, Math.floor(d.percent || 0))),
            active: !!d.active,
            contested: !!d.contested,

            attackerGangId: d.attackerGangId || 0,
            attackerGangName: d.attackerGangName || '',

            // owner == defender during capture; after capture server sends attacker as defender
            defenderGangId: ownerGangId,
            defenderGangName: ownerGangName,

            // expose colors under ALL aliases GangClaimView understands
            defenderPrimaryColor: primary,
            defenderSecondaryColor: secondary,
            ownerPrimaryColor: primary,
            ownerSecondaryColor: secondary,
            ownerClrA: primary,
            ownerClrB: secondary,
        };

        // seed a tiny global cache so views can recover colors later if needed
        try {
            (window as any).__gangColorMap =
                (window as any).__gangColorMap || {};
            if (ownerGangId > 0 && primary && secondary) {
                (window as any).__gangColorMap[ownerGangId] = {
                    primary,
                    secondary,
                };
            }
        } catch {}

        window.dispatchEvent(
            new CustomEvent('turf_capture_progress', { detail: payload })
        );
        window.dispatchEvent(
            new CustomEvent('turf_capture_status', { detail: payload })
        );
    }

