    private onGuideStartEvent(event: QuickGuideEvent): void {
        const parser = event.getParser();
        if (!parser) return;

        // Fire the overlay you already have wired in OnboardingOverlay.tsx
        window.dispatchEvent(new Event('start_quick_guide'));
    }

    private onHotRoomsListEvent(event: HotRoomsListMessageEvent): void {
        const parser = event.getParser();
        if (!parser) return;

        const rooms = parser.rooms;

        // Send data first
        window.dispatchEvent(
            new CustomEvent('hot_rooms_update', { detail: rooms })
        );

        // Then open the view
        window.dispatchEvent(new Event('open_hot_rooms'));
    }
    private onClickThroughStateEvent(event: ClickThroughStateEvent): void {
        const parser = event.getParser();
        if (!parser) return;

        const enabled = parser.enabled;

        // Global toggle (kept here too so it works even if parser stops doing it)
        (window as any).__ctEnabled = enabled;
        document.documentElement.classList.toggle('ct-on', enabled);
        console.log('clickthrough bridge sent');

        // Fire a UI bridge event for React/Vue/etc.
        window.dispatchEvent(
            new CustomEvent('click_through_state', { detail: { enabled } })
        );

        // (optional) toast/snackbar
        window.dispatchEvent(
            new CustomEvent('nitro_alert', {
                detail: enabled
                    ? 'Click-through enabled'
                    : 'Click-through disabled',
            })
        );
    }

    private onInventoryItemsEvent(event: InventoryMessageEvent): void {
        const parser = event.getParser();
        if (!parser) return;

        const items: InventoryContext[] = parser.items.map((item: any) => ({
            id: item.id,
            item_id: item.item_id,
            user_id: item.user_id,
            slot: item.slot,
            quantity: item.quantity,

            durability: item.durability,
            // ✅ correct key; optional fallback to legacy naming if present
            max_durability: item.max_durability ?? item.durability_max ?? 100,

            name: item.name,
            item_type: item.item_type,
            rarity: item.rarity,
            icon_path: item.icon_path,

            // keep extras if you use them; they won’t hurt
            last_used_at: item.last_used_at,
            description: item.description,
            cooldown_seconds: item.cooldown_seconds,
            damage_increase: item.damage_increase,
            health_increase: item.health_increase,
            max_stack: item.max_stack,
            created_at: item.created_at,
            stats: item.stats,
        }));

        console.log('Received Inventory:', items);

        // Make sure InventoryStore.setItems expects the InventoryContext shape with `max_durability`
        InventoryStore.setItems(items);

        window.dispatchEvent(new CustomEvent('inventory_update'));
    }

    private onOpponentStatsEvent(event: OpponentStatsEvent): void {
        const p = event.getParser();
        if (!p) return;

        const payload = {
            userId: p.userId,
            username: p.username,
            figure: p.figure,

            health: p.health,
            maxHealth: p.maxHealth,
            energy: p.energy,
            maxEnergy: p.maxEnergy,
            hunger: p.hunger,
            maxHunger: p.maxHunger,

            aggressionMs: p.aggressionMs,

            // xp / stats
            xp: p.xp,
            maxXP: p.maxXP,
            level: p.level,
            points: p.points,

            strength: p.strength,
            stamina: p.stamina,
            defense: p.defense,
            gathering: p.gatheringLevel,
            healthlevel: p.healthLevel,

            // fighting stats in canonical names
            punches: p.punchesThrown,
            damageGiven: p.damageDealt,
            damageReceived: p.damageReceived,
            kills: p.kills,
            deaths: p.deaths,

            shiftsWorked: p.shiftsWorked,
            arrests: p.arrests,

            isAggressive: p.isAggressive,

            // employment
            jobTitle: p.jobTitle,
            corporationName: p.corporationName,
            corporationIconUrl: p.corporationIconUrl,

            // gang
            gangId: p.gangId,
            gangName: p.gangName,
            gangIconKey: p.gangIconKey,
            gangPrimaryColor: p.gangPrimaryColor,
            gangSecondaryColor: p.gangSecondaryColor,
        };

        window.dispatchEvent(
            new CustomEvent('open-opponent-stats', { detail: payload })
        );
        window.dispatchEvent(
            new CustomEvent('user_inspect_stats', { detail: payload })
        );
        window.dispatchEvent(
            new CustomEvent('opponent_stats_update', { detail: payload })
        );
    }

